}
const programInsights = normalizeList(readFirst(programData, ["programInsights"], []));
const publisherInsights = normalizeList(readFirst(publisherData, ["publisherInsights"], []));

const slideBlueprint = [
  { slide: 1, key: "cover", title: "Quarterly Business Review Cover" },
  { slide: 2, key: "reporting_overview", title: "Reporting Period Overview" },
  { slide: 3, key: "program_exec_summary", title: "Program Performance Executive Summary" },
  { slide: 4, key: "kpi_volume_conversion", title: "KPI Summary - Volume & Conversion" },
  { slide: 5, key: "kpi_cost_roi", title: "KPI Summary - Cost, CPA & ROI" },
  { slide: 6, key: "kpi_implications", title: "KPI Highlights & Business Implications" },
  { slide: 7, key: "publisher_overview", title: "Publisher Performance Overview" },
  { slide: 8, key: "movers_sales", title: "Movers & Shakers - Sales" },
