  { slide: 13, key: "brand_new_publishers", title: "Brand New Publishers" },
  { slide: 14, key: "new_emerging_publishers", title: "New & Emerging Publishers" },
  { slide: 15, key: "recommendations", title: "Strategic Recommendations" },
  { slide: 16, key: "risks_dependencies", title: "Risks & Dependencies" },
