const inputItems = $input.all();
const requestItems = (() => {
  try {
    return $items("Init Publisher Current Requests").map((item) => item.json || {});
  } catch {
    return [];
  }
})();
const allItems = [];

function rowsFromResponse(response) {
  if (Array.isArray(response.items)) return response.items;
  if (Array.isArray(response.data)) return response.data;
  if (Array.isArray(response.rows)) return response.rows;
  if (Array.isArray(response)) return response;
  return [];
}

function pairedRequestIndex(item, fallbackIndex) {
  const paired = Array.isArray(item.pairedItem) ? item.pairedItem[0] : item.pairedItem;
  const index = Number(paired?.item);
  return Number.isInteger(index) && index >= 0 ? index : fallbackIndex;
}

function asText(value, fallback = "") {
  if (value === null || value === undefined) return fallback;
  const text = String(value).trim();
  return text || fallback;
}

inputItems.forEach((inputItem, fallbackIndex) => {
  const response = inputItem.json || {};
  const request = requestItems[pairedRequestIndex(inputItem, fallbackIndex)] || {};
  const requestProgramId = asText(response.programId || response.request?.programId || request.programId);
  const requestProgramName = asText(response.programName || response.request?.programName || request.programName);
  const rows = rowsFromResponse(response);

  for (const row of rows) {
    if (!row || typeof row !== "object" || Array.isArray(row)) continue;
    allItems.push({
      ...row,
      programId: asText(row.programId || row.program?.id || row.advertiserProgramId || requestProgramId),
      programName: asText(row.programName || row.program?.name || row.advertiserProgramName || requestProgramName),
    });
  }
});

return [{
  json: {
    items: allItems,
    allItems,
    requestCount: inputItems.length,
    rowsWithProgramId: allItems.filter((item) => asText(item.programId)).length
  }
}];

